#include <bits/stdc++.h>
using namespace std;
const int mod=1e9+7;
map<int,long long> mp;
int n,a[100005],mx=0,mn=1e9;
long long ans;
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        mp[a[i]]++,mx=max(mx,a[i]),mn=min(mn,a[i]);
    }
    for(int i=mn;i<=mx;i++){
        if(mp[i]>1)
            for(int j=1;j<=i/2;j++){
            	if(2*j==i)
            		ans+=max(1LL*0,1LL*(mp[i]*(mp[i]-1)/2%mod)*((mp[j]-1)*mp[j]/2%mod)),ans%=mod;
				else
                	ans+=1LL*(mp[i]*(mp[i]-1)/2%mod)*(mp[j]*mp[i-j]%mod),ans%=mod;
            }
    }
    printf("%lld",ans); 
    return 0;
}
